    }
    __typename
  }
}
"},{"operationName":"DisableCheck","variables":{},"query":"query DisableCheck {
  feature(key: "EmergencyNotice")
  league(id: 589) {
    news(limit: 1) {
      id
      title
      __typename
    }
    __typename
  }
}
"},{"operationName":"TournamentBannerQuery","variables":{},"query":"query TournamentBannerQuery {
  viewer {
    id
    ... on Member {
      registrationWindows(status: [IN_PROGRESS, CLOSED]) {
        id
        tournamentPlayers(mine: true, registered: false) {
          ... on TeamTournamentPlayer {
            id
            __typename
          }
          ... on SinglesTournamentPlayer {
            id
            __typename
          }
          ... on WeeklyTournamentPlayer {
            id
            __typename
          }
          ... on USAMTournamentPlayer {
            id
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"MembershipBannerQuery","variables":{},"query":"query MembershipBannerQuery {
  viewer {
    ... on Member {
      id
      fee {
        message
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"ViewerQuery","variables":{},"query":"query ViewerQuery {
  viewer {
    __typename
    id
    firstName
    lastName
    emailAddress
  }
}
"},{"operationName":"FeatureCheck","variables":{},"query":"query FeatureCheck {
  features {
    id
    name
    active
    __typename
  }
}
"},{"operationName":"UseGetViewerQuery","variables":{},"query":"query UseGetViewerQuery {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"RaygunUserTracking","variables":{},"query":"query RaygunUserTracking {
