[{"operationName":"viewerCountryQuery","variables":{},"query":"query viewerCountryQuery {
  viewer {
    id
    ... on Member {
      country {
        id
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"Header","variables":{},"query":"query Header {
  viewer {
    id
    initials
    __typename
  }
}
"},{"operationName":"notificationBell","variables":{},"query":"query notificationBell {
  viewer {
    id
    notificationBellCount
    notifications(limit: 10) {
      id
      type
      title
      body
      isRead
      createdDate
      typeId
      metaData
      __typename
    }
    __typename
  }
}
"},{"operationName":"HeaderCartQueryQuery","variables":{},"query":"query HeaderCartQueryQuery {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        name
        isDefault
        isElectronicPaymentsEnabled
        __typename
      }
      membershipExpires
      setting(key: "DefaultLeague")
      fee {
        message
        discount
        year
        amount
        tax
        total
        __typename
      }
      leagues {
        id
        country {
          id
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"ComponentFeatureCheck","variables":{"key":"Search"},"query":"query ComponentFeatureCheck($key: String!) {
  feature(key: $key)
}
"},{"operationName":"LiveStream","variables":{},"query":"query LiveStream {
  liveStream {
    __typename
    feeds {
      __typename
      ... on YoutubeLive {
        title
        description
        publishTime
        embed
        thumbnails {
          url
          height
          width
          __typename
        }
        __typename
      }
    }
  }
}
"},{"operationName":"getMemberStatsHeader","variables":{"id":3031992},"query":"query getMemberStatsHeader($id: Int!) {
  member(id: $id) {
    id
    firstName
    lastName
    initials
    aliases(includeInactive: true) {
      id
      displayName
      memberNumber
      league {
        id
        slug
        name
        isDefault
        number
        __typename
      }
      formats
      stats {
        __typename
        skillLevel
        CLA
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"TournamentStatQuery","variables":{"id":3031992,"limit":5,"offset":0},"query":"query TournamentStatQuery($id: Int!, $limit: Int!, $offset: Int!) {
  member(id: $id) {
    id
    playerTournaments(limit: $limit, offset: $offset) {
      ... on TeamPlayerTournament {
        __typename
        id
        teamNumber
        skillLevel
        standing
        teamName
        disqualified
        tournament {
          name
          id
          startTime
          type: formatType
          __typename
        }
      }
      ... on SinglesPlayerTournament {
        id
        skillLevel
        standing
        disqualified
        tournament {
          name
          id
          startTime
          type: formatType
          __typename
        }
        __typename
      }
      ... on USAMPlayerTournament {
        id
        standing
        disqualified
        tournament {
          id
          name
          startTime
          type: formatType
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]

